const CLAUDE_API_URL = 'https://api.anthropic.com/v1/messages';
const MODEL = 'claude-sonnet-4-20250514';

async function callClaude(systemPrompt, userPrompt) {
  const response = await fetch(CLAUDE_API_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-calls': 'true',
    },
    body: JSON.stringify({
      model: MODEL,
      max_tokens: 2000,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }],
    }),
  });

  if (!response.ok) {
    const err = await response.json();
    throw new Error(err?.error?.message || 'Claude API error');
  }

  const data = await response.json();
  const text = data.content?.[0]?.text || '';
  // Strip any markdown code fences
  const clean = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  return JSON.parse(clean);
}

export async function generateRoadmap({ jobRole, jobDescription, experienceLevel, currentSkills }) {
  const systemPrompt = `You are an expert career coach and curriculum designer. 
Generate a structured learning roadmap as pure JSON only. No markdown, no explanation, just the JSON object.`;

  const input = jobRole
    ? `Job Role: ${jobRole}`
    : `Job Description: ${jobDescription}`;

  const userPrompt = `Generate a personalized learning roadmap for:
${input}
Experience Level: ${experienceLevel}
Current Skills: ${currentSkills.length > 0 ? currentSkills.join(', ') : 'None'}

Return ONLY this JSON structure (no markdown, no backticks):
{
  "targetRole": "string",
  "totalWeeks": number,
  "phases": [
    {
      "id": number,
      "title": "string",
      "weeks": number,
      "status": "in_progress" | "not_started",
      "topics": ["string"],
      "description": "string"
    }
  ],
  "courses": [
    {
      "id": "string",
      "title": "string",
      "phase": number,
      "phaseLabel": "string",
      "difficulty": "Beginner" | "Intermediate" | "Advanced",
      "hours": number,
      "progress": number,
      "description": "string"
    }
  ],
  "skillGap": [
    {
      "skill": "string",
      "yourLevel": number,
      "required": number,
      "gap": "High" | "Medium" | "Low"
    }
  ],
  "stats": {
    "skillsToMaster": number,
    "estimatedWeeks": number,
    "coursesAvailable": number,
    "completionPercent": number
  }
}

Make it realistic for a ${experienceLevel} targeting ${jobRole || 'the role'}. Include 4 phases and 6 courses minimum.`;

  return callClaude(systemPrompt, userPrompt);
}

export async function analyzeSkillGap({ targetRole, currentSkills, experienceLevel }) {
  const systemPrompt = `You are a technical skills assessor. Return pure JSON only, no markdown.`;

  const userPrompt = `Analyze skill gap for:
Target Role: ${targetRole}
Current Skills: ${currentSkills.join(', ')}
Experience Level: ${experienceLevel}

Return ONLY this JSON (no markdown):
{
  "skillGap": [
    {
      "skill": "string",
      "yourLevel": number (1-5),
      "required": number (1-5),
      "gap": "High" | "Medium" | "Low"
    }
  ],
  "recommendations": [
    {
      "title": "string",
      "gap": "High" | "Medium" | "Low",
      "hours": number
    }
  ]
}`;

  return callClaude(systemPrompt, userPrompt);
}
